// export default Taskcard


import React from 'react'

const Taskcard = ({ task }) => {
    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>
                        {task.title}
                    </div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button' type="button">
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button' type="button">
                                <img className='icon-img' src='/assets/edit.png' alt="Edit" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button' type="button">
                                <img className='icon-img' src='/assets/delete.png' alt="Delete" />
                            </button>
                        </div>
                    </div>
                </div>

                <div className='sub-tasks'>
                    <ul>
                        {task.subtasks && task.subtasks.length > 0 ? (
                            task.subtasks.map(subtask => (
                                <li key={subtask.id}>
                                    <label>
                                        <input 
                                            type="checkbox" 
                                            checked={subtask.completed} 
                                            readOnly 
                                        />
                                        {' '}{subtask.title}
                                    </label>
                                </li>
                            ))
                        ) : (
                            <li>No subtasks</li>
                        )}
                    </ul>
                </div>
            </div>
            <Stylesheet />
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
        .task-card {
            margin-bottom: 2rem;
            width: 270px;
            border: 1px solid #ccc;
            border-radius: 5px;
            padding: 10px;
            background-color: var(--secondary-color, #f9f9f9);
            box-sizing: border-box;
        }
        .taskcard-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 5px 10px;
            background-color: var(--secondary-color);
            border-radius: 5px;
            min-height: 50px;
        }
        .task-title {
            width: 100px;
            white-space: normal;
            overflow-wrap: break-word;
            word-break: break-word;
            font-weight: bold;
        }
        .task-icons {
            display: flex;
            align-items: center;
            gap: 8px;
        }
        .icon-button {
            background: none;
            border: none;
            cursor: pointer;
            padding: 0;
        }
        .icon-img {
            height: 20px;
            width: 30px;
        }
        .sub-tasks {
            margin-top: 10px;
            background-color: yellow;
            padding: 5px 10px;
            border-radius: 5px;
        }
        .sub-tasks ul {
            list-style-type: disc;
            padding-left: 20px;
            margin: 0;
        }
        .sub-tasks li {
            margin-bottom: 6px;
            font-size: 14px;
        }
        .sub-tasks input[type="checkbox"] {
            margin-right: 8px;
            cursor: pointer;
        }
    `}</style>
}

export default Taskcard
